package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Component
public class IdTokenClaimsParser {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenClaimsParser.class);

    private final OidcProperties oidcProperties;

    public IdTokenClaimsParser(OidcProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
    }

    public UserSession parseIdToken(OidcUser oidcUser) {
        OidcIdToken idToken = oidcUser.getIdToken();

        validateIssuer(idToken);
        validateTokenExpiration(idToken);
        validateAudience(idToken);

        String subject = sanitizeClaim(idToken.getSubject());
        String email = sanitizeClaim(idToken.getEmail());
        String name = sanitizeClaim(idToken.getFullName());
        String preferredUsername = sanitizeClaim(idToken.getPreferredUsername());
        String issuer = idToken.getIssuer() != null ? idToken.getIssuer().toString() : null;

        Set<String> roles = extractRoles(idToken);

        Instant tokenExpiration = idToken.getExpiresAt();
        Instant authenticatedAt = idToken.getAuthenticatedAt() != null ?
            idToken.getAuthenticatedAt() : Instant.now();

        Map<String, Object> additionalClaims = extractAdditionalClaims(idToken);

        logger.info("Parsed ID token for subject: {}", subject);

        return UserSession.builder()
            .subject(subject)
            .email(email)
            .name(name)
            .preferredUsername(preferredUsername)
            .roles(roles)
            .authenticatedAt(authenticatedAt)
            .tokenExpiration(tokenExpiration)
            .issuer(issuer)
            .additionalClaims(additionalClaims)
            .build();
    }

    private void validateIssuer(OidcIdToken idToken) {
        if (idToken.getIssuer() == null) {
            throw new SecurityException("ID token missing issuer claim");
        }

        List<String> allowedIssuers = oidcProperties.getAllowedIssuers();
        if (allowedIssuers != null && !allowedIssuers.isEmpty()) {
            String issuer = idToken.getIssuer().toString();
            if (!allowedIssuers.contains(issuer)) {
                logger.error("Untrusted issuer detected: {}", issuer);
                throw new SecurityException("Untrusted token issuer: " + issuer);
            }
        }
    }

    private void validateTokenExpiration(OidcIdToken idToken) {
        if (idToken.getExpiresAt() == null) {
            throw new SecurityException("ID token missing expiration claim");
        }

        Instant now = Instant.now();
        long clockSkew = oidcProperties.getTokenClockSkewSeconds();
        if (now.isAfter(idToken.getExpiresAt().plusSeconds(clockSkew))) {
            logger.error("Expired ID token detected for subject: {}", idToken.getSubject());
            throw new SecurityException("ID token has expired");
        }
    }

    private void validateAudience(OidcIdToken idToken) {
        if (idToken.getAudience() == null || idToken.getAudience().isEmpty()) {
            throw new SecurityException("ID token missing audience claim");
        }
    }

    @SuppressWarnings("unchecked")
    private Set<String> extractRoles(OidcIdToken idToken) {
        Set<String> roles = new HashSet<>();

        // Try extracting from realm_access (Keycloak style)
        Object realmAccess = idToken.getClaim("realm_access");
        if (realmAccess instanceof Map) {
            Map<String, Object> realmAccessMap = (Map<String, Object>) realmAccess;
            Object rolesObj = realmAccessMap.get("roles");
            if (rolesObj instanceof Collection) {
                ((Collection<?>) rolesObj).forEach(role -> {
                    if (role instanceof String) {
                        roles.add(sanitizeClaim((String) role));
                    }
                });
            }
        }

        // Try extracting from "roles" claim directly
        Object rolesClaim = idToken.getClaim("roles");
        if (rolesClaim instanceof Collection) {
            ((Collection<?>) rolesClaim).forEach(role -> {
                if (role instanceof String) {
                    roles.add(sanitizeClaim((String) role));
                }
            });
        }

        // Try extracting from "groups" claim
        Object groupsClaim = idToken.getClaim("groups");
        if (groupsClaim instanceof Collection) {
            ((Collection<?>) groupsClaim).forEach(group -> {
                if (group instanceof String) {
                    roles.add(sanitizeClaim((String) group));
                }
            });
        }

        return roles;
    }

    private Map<String, Object> extractAdditionalClaims(OidcIdToken idToken) {
        Set<String> standardClaims = Set.of(
            "sub", "iss", "aud", "exp", "iat", "auth_time", "nonce",
            "acr", "amr", "azp", "email", "email_verified",
            "name", "preferred_username", "given_name", "family_name",
            "realm_access", "roles", "groups"
        );

        Map<String, Object> additional = new HashMap<>();
        if (idToken.getClaims() != null) {
            idToken.getClaims().forEach((key, value) -> {
                if (!standardClaims.contains(key)) {
                    additional.put(key, value);
                }
            });
        }
        return additional;
    }

    private String sanitizeClaim(String value) {
        if (value == null) {
            return null;
        }
        // Remove control characters and trim
        return value.replaceAll("[\\p{Cntrl}]", "").trim();
    }
}

