package com.example.oidcclient.security;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.util.Collection;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

@Service
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final IdTokenClaimsParser claimsParser;

    public CustomOidcUserService(IdTokenClaimsParser claimsParser) {
        this.claimsParser = claimsParser;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        try {
            OidcUser oidcUser = super.loadUser(userRequest);

            // Parse and validate the ID token claims
            var userSession = claimsParser.parseIdToken(oidcUser);

            logger.info("Successfully loaded OIDC user: subject={}, email={}",
                userSession.getSubject(), userSession.getEmail());

            // Build enhanced authorities from roles
            Set<GrantedAuthority> authorities = new HashSet<>(oidcUser.getAuthorities());
            userSession.getRoles().forEach(role -> {
                String normalizedRole = role.toUpperCase();
                if (!normalizedRole.startsWith("ROLE_")) {
                    normalizedRole = "ROLE_" + normalizedRole;
                }
                authorities.add(new SimpleGrantedAuthority(normalizedRole));
            });

            return new DefaultOidcUser(
                authorities,
                oidcUser.getIdToken(),
                oidcUser.getUserInfo(),
                "sub"
            );

        } catch (SecurityException e) {
            logger.error("Security validation failed during OIDC user loading: {}", e.getMessage());
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_token", e.getMessage(), null));
        } catch (Exception e) {
            logger.error("Failed to load OIDC user: {}", e.getMessage(), e);
            throw new OAuth2AuthenticationException(
                new OAuth2Error("user_loading_error", "Failed to process authentication", null));
        }
    }
}

