package com.example.oidcclient.security;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.logout.LogoutHandler;
import org.springframework.stereotype.Component;

@Component
public class OidcLogoutHandler implements LogoutHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcLogoutHandler.class);

    @Override
    public void logout(HttpServletRequest request, HttpServletResponse response,
                       Authentication authentication) {
        if (authentication != null && authentication.getPrincipal() instanceof OidcUser oidcUser) {
            logger.info("Logging out user: {}", oidcUser.getSubject());
        }

        HttpSession session = request.getSession(false);
        if (session != null) {
            session.removeAttribute("USER_SESSION");
            session.invalidate();
            logger.info("Session invalidated during logout");
        }
    }
}

