package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSession;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class HomeController {

    @GetMapping("/")
    public String home() {
        return "home";
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser,
                            HttpSession session, Model model) {
        UserSession userSession = (UserSession) session.getAttribute("USER_SESSION");

        if (userSession != null) {
            model.addAttribute("userSession", userSession);
            model.addAttribute("subject", userSession.getSubject());
            model.addAttribute("email", userSession.getEmail());
            model.addAttribute("name", userSession.getName());
            model.addAttribute("roles", userSession.getRoles());
        }

        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser,
                          HttpSession session, Model model) {
        UserSession userSession = (UserSession) session.getAttribute("USER_SESSION");

        if (userSession != null) {
            model.addAttribute("userSession", userSession);
            model.addAttribute("claims", userSession.getAdditionalClaims());
            model.addAttribute("tokenExpiration", userSession.getTokenExpiration());
            model.addAttribute("authenticatedAt", userSession.getAuthenticatedAt());
            model.addAttribute("issuer", userSession.getIssuer());
        }

        return "profile";
    }
}

