public class UserInfoController {

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> getUserInfo(
            @AuthenticationPrincipal OidcUser oidcUser, HttpSession session) {

        UserSession userSession = (UserSession) session.getAttribute("USER_SESSION");

        if (userSession == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("subject", userSession.getSubject());
        userInfo.put("email", userSession.getEmail());
        userInfo.put("name", userSession.getName());
        userInfo.put("preferredUsername", userSession.getPreferredUsername());
        userInfo.put("roles", userSession.getRoles());
        userInfo.put("issuer", userSession.getIssuer());
        userInfo.put("authenticatedAt", userSession.getAuthenticatedAt());
        userInfo.put("tokenExpired", userSession.isTokenExpired());

        return ResponseEntity.ok(userInfo);
    }
}

